wolfram_code:
Module[{b3, kGimel, kGimelExpected, sumMnu, planckBound, oscLowerNH, oscLowerIO, desiBound, approxScale, tension, inWindow, status},
  (* G2 manifold Pillar Seeds *)
  b3 = 24;
  kGimel = b3/2 + 1/Pi; (* = 12.31831... from FormulasRegistry *)

  (* k_gimel cross-check *)
  kGimelExpected = 24/2 + 1/Pi;
  Assert[kGimel == kGimelExpected];

  (* Hopf fibration formula: Sum(m_nu) = k_gimel / (2*Pi*b3) *)
  sumMnu = kGimel / (2*Pi*b3);

  (* Experimental bounds *)
  planckBound = 0.12;    (* eV, Planck+BAO 2018, 95% CL *)
  oscLowerNH = 0.058;    (* eV, oscillation floor NH from NuFit 6.0 *)
  oscLowerIO = 0.098;    (* eV, oscillation floor IO from NuFit 6.0 *)
  desiBound = 0.072;     (* eV, DESI+CMB+BAO 2024, 95% CL upper bound *)
  approxScale = 0.02;    (* eV, approximate analysis scale *)

  tension = Abs[sumMnu - desiBound] / approxScale;
  inWindow = (oscLowerNH < sumMnu < planckBound);
  status = If[inWindow, "LOCKED", "FAILED"];

  (* Note: sumMnu < oscLowerIO means this prediction is incompatible with IO *)
  {N[sumMnu, 4], N[tension, 2], status}
]
